$content = Get-Content app\(site)\off-plan\OffPlanClient.tsx -Raw
$content = $content -replace '(<div className="flex">)', '<div className="flex flex-col md:flex-row bg-[#F9FAFB]">'
$content = $content -replace '(<div className="w-\[58%\] p-6 grid grid-cols-2 gap-5 content-start">)', '<div className={"order-2 md:order-1 w-full md:w-[58%] p-4 md:p-8 grid grid-cols-1 sm:grid-cols-2 gap-6 md:gap-8 content-start " + (mobileView === "map" ? "hidden md:grid" : "grid")}><div className="col-span-1 sm:col-span-2 border-t border-black/5 pt-8 md:hidden mt-2 mb-2 flex items-center justify-between"><h2 className="font-display text-3xl font-bold text-black tracking-tight">Listings</h2><span className="font-body text-xs font-bold uppercase tracking-widest text-black/50">{filtered.length} found</span></div>'
$content = $content -replace '(<div className="w-\[42%\] sticky top-\[var\(--nav-height\)\]\r?\nh-\[calc\(100vh-var\(--nav-height\)\)\] shrink-0">)', '<div className={"order-1 md:order-2 w-full h-[calc(100vh-var(--nav-height))] md:w-[42%] md:m-0 md:h-[calc(100vh-var(--nav-height))] md:max-h-none sticky top-auto md:top-[var(--nav-height)] z-10 shrink-0 overflow-hidden md:rounded-none md:rounded-l-[32px] border border-black/10 md:border-y-0 md:border-r-0 md:border-l shadow-2xl md:shadow-sm " + (mobileView === "list" ? "hidden md:block" : "block")}>'
$content = $content -replace '\{/\* ── Results bar .*?\s*\*/\}\s*<div className="border-b border-black/6 px-6 py-3 flex items-center">\s*<span className="text-\[13px\] text-black/50 font-medium">\s*\{filtered\.length\}.*?\s*</span>\s*</div>', ''
Set-Content "app\(site)\off-plan\OffPlanClient.tsx" $content
